import{_ as o,o as t,c as a,ae as r}from"./chunks/framework.EHGTsUvI.js";const c=JSON.parse(`{"title":"Making a blog","description":"","frontmatter":{"headerImage":"https://images.unsplash.com/photo-1542435503-956c469947f6?ixlib=rb-1.2.1&ixid=MnwxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8&auto=format&fit=crop&w=2574&q=80","title":"Making a blog","published":true,"date":"2021-12-07T13:20:00.000Z","excerpt":"We're making a blog with Gridsome! Looking at how to use local files as a data source."},"headers":[],"relativePath":"blog/gridsome_blog.md","filePath":"blog/gridsome_blog.md"}`),s={name:"blog/gridsome_blog.md"};function i(l,e,n,d,p,u){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="intro" tabindex="-1">Intro <a class="header-anchor" href="#intro" aria-label="Permalink to &quot;Intro&quot;">​</a></h1><p>This is really just a test, there are plenty of <a href="https://gridsome.org/starters/platform/markdown/" target="_blank" rel="noreferrer">good resources on how to create a blog using Gridsome</a>.</p><h2 id="setup" tabindex="-1">Setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;Setup&quot;">​</a></h2><p>The quick version is to just use a starter project, but lets do an overview of some things anyway.</p><p>Start a new Gridsome project by using <code>gridsome create my-gridsome-blog</code>.</p><p>You&#39;ll be needing a page to show a list of your blog posts, here we&#39;ll query out blog posts. Then a template to show each post individually, here we&#39;ll query specific individual posts.</p><p>To be able to query your blog posts from a local source, you&#39;ll need to use the <a href="https://gridsome.org/docs/fetching-data/#markdown" target="_blank" rel="noreferrer">source plugin</a>. I&#39;ve setup this blog to use markdown, you can choose a different configuration though.</p>',7)])])}const h=o(s,[["render",i]]);export{c as __pageData,h as default};
